1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	export function claimOffice(request: any): any {
17	  const customer = request.customer;
18	  const results: any[] = [];
19	
20	  for (let stepIndex = 0; stepIndex < request.steps.length; stepIndex++) {
21	    const items = request.steps[stepIndex].items;
22	
23	    const componentCounts: Record<string, number> = {};
24	    for (const item of items) {
25	      if (COMPONENT_TYPES.has(item.type)) {
26	        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
27	      }
28	    }
29	
30	    let totalPremium = 0;
31	    let policyBasePremium = 0;
32	    const blocksApplied = new Set<string>();
33	
34	    for (const item of items) {
35	      const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
36	      if (isBlock && !blocksApplied.has(item.type)) {
37	        totalPremium += BLOCK_PREMIUM;
38	        policyBasePremium += BASE_PREMIUMS[item.type] * BLOCK_SIZE;
39	        blocksApplied.add(item.type);
40	      } else if (!isBlock) {
41	        let itemPremium = BASE_PREMIUMS[item.type];
42	        policyBasePremium += BASE_PREMIUMS[item.type];
43	        if (item.cursed) {
44	          itemPremium += BASE_PREMIUMS[item.type] * 0.5;
45	        }
46	        if (item.enchantment >= 5) {
47	          itemPremium += BASE_PREMIUMS[item.type] * 0.3;
48	        }
49	        totalPremium += itemPremium;
50	      }
51	    }
52	
53	    if (customer.yearsWithMHPCO >= 2) {
54	      totalPremium -= policyBasePremium * 0.2;
55	    }
56	
57	    totalPremium += policyBasePremium * 0.1;
58	
59	    if (stepIndex > 0) {
60	      totalPremium -= policyBasePremium * 0.15;
61	    }
62	
63	    results.push({ premium: Math.ceil(totalPremium + PROCESSING_FEE) });
64	  }
65	
66	  return results;
67	}
